import { useState } from 'react'
import { quizData } from '@/data/quiz'
import { useStore } from '@/store/useStore'

// 营养问答每题20分
const POINTS_PER_QUESTION = 20

export default function Quiz() {
  const { quizScore, addQuizScore, addQuizAnswered, resetQuiz, addSectionScore, resetSectionScore } = useStore()
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0)
  const [selectedAnswer, setSelectedAnswer] = useState<number | null>(null)
  const [showExplanation, setShowExplanation] = useState(false)
  const [earnedScore, setEarnedScore] = useState(0)

  const total = quizData.length
  const isFinished = currentQuestionIndex >= total
  const currentQuestion = quizData[currentQuestionIndex]

  const handleSelect = (index: number) => {
    if (selectedAnswer !== null) return
    setSelectedAnswer(index)
    setShowExplanation(true)
    addQuizAnswered()

    if (index === currentQuestion.correctIndex) {
      addQuizScore()
      addSectionScore('quiz', POINTS_PER_QUESTION)
      setEarnedScore(prev => prev + POINTS_PER_QUESTION)
    }

    setTimeout(() => {
      setCurrentQuestionIndex((prev) => prev + 1)
      setSelectedAnswer(null)
      setShowExplanation(false)
    }, 2000)
  }

  const handleRetry = () => {
    // 只清零营养问答环节的分数
    resetSectionScore('quiz')
    resetQuiz()
    setCurrentQuestionIndex(0)
    setSelectedAnswer(null)
    setShowExplanation(false)
    setEarnedScore(0)
  }

  const getOptionStyle = (index: number) => {
    if (selectedAnswer === null) return 'bg-white border-gray-200 active:scale-95'
    if (index === currentQuestion.correctIndex) return 'bg-green-100 border-green-500 text-green-700'
    if (index === selectedAnswer) return 'bg-red-100 border-red-500 text-red-700'
    return 'bg-white border-gray-200 opacity-50'
  }

  if (isFinished) {
    return (
      <div className="page-section flex flex-col items-center justify-center px-6"
        style={{ background: 'linear-gradient(180deg, #E3F2FD 0%, #ffffff 100%)' }}>
        <div className="text-6xl mb-4">🎉</div>
        <h2 className="text-2xl font-bold text-gray-800 mb-2">答题完成！</h2>
        <p className="text-lg text-gray-600 mb-6">
          答对 <span className="text-green-600 font-bold">{quizScore}</span>/{total} 题
        </p>
        <div className="bg-white rounded-2xl shadow-lg p-6 w-full max-w-xs mb-6">
          <div className="text-center">
            <p className="text-gray-500 text-sm mb-1">获得积分</p>
            <p className="text-3xl font-bold text-green-600">{earnedScore}</p>
          </div>
        </div>
        <p className="text-gray-400 text-xs mb-4">（再试一次仅清零本环节积分）</p>
        <button onClick={handleRetry}
          className="px-8 py-3 rounded-full text-white font-bold text-lg
            bg-gradient-to-r from-blue-400 to-blue-500 shadow-lg active:scale-95 transition-transform">
          再试一次
        </button>
      </div>
    )
  }

  return (
    <div className="page-section flex flex-col px-5 py-6"
      style={{ background: 'linear-gradient(180deg, #E3F2FD 0%, #ffffff 100%)' }}>
      <div className="w-full h-2 bg-gray-200 rounded-full mb-4 overflow-hidden">
        <div className="h-full bg-gradient-to-r from-blue-400 to-blue-600 rounded-full transition-all duration-500"
          style={{ width: `${((currentQuestionIndex + 1) / total) * 100}%` }} />
      </div>

      <h2 className="text-2xl font-bold text-center text-gray-800 mb-1">营养问答</h2>
      <p className="text-center text-gray-400 text-xs mb-3">答对每题 +{POINTS_PER_QUESTION}分</p>

      <div className="flex justify-center mb-3">
        <span className="bg-blue-500 text-white text-sm font-bold px-3 py-1 rounded-full">
          {currentQuestionIndex + 1}/{total}
        </span>
      </div>

      <div className="bg-white rounded-2xl shadow-lg p-5 mb-4">
        <div className="flex items-center justify-between mb-3">
          <p className="text-lg font-bold text-gray-800 flex-1">{currentQuestion.question}</p>
          <span className="bg-blue-100 text-blue-600 text-xs font-bold px-2 py-1 rounded-full ml-2">
            +{POINTS_PER_QUESTION}分
          </span>
        </div>
        <div className="flex flex-col gap-3">
          {currentQuestion.options.map((option, index) => (
            <button key={index} onClick={() => handleSelect(index)} disabled={selectedAnswer !== null}
              className={`w-full text-left px-4 py-3 rounded-xl border-2 font-medium transition-all duration-300 ${getOptionStyle(index)}`}>
              {option}
            </button>
          ))}
        </div>
      </div>

      {showExplanation && (
        <div className={`rounded-xl p-4 mx-1 text-sm leading-relaxed transition-all duration-300 ${
          selectedAnswer === currentQuestion.correctIndex
            ? 'bg-green-50 text-green-800 border border-green-200'
            : 'bg-red-50 text-red-800 border border-red-200'}`}>
          {selectedAnswer === currentQuestion.correctIndex
            ? `回答正确！+${POINTS_PER_QUESTION}分 `
            : '答错啦！'}
          {currentQuestion.explanation}
        </div>
      )}
    </div>
  )
}
