import { useState } from 'react'
import { useStore } from '@/store/useStore'

// DIY保存+20分
const DIY_POINTS = 20

const colors = [
  { name: '绿色', value: '#00A850' },
  { name: '粉色', value: '#FF9ECD' },
  { name: '棕色', value: '#8B5E3C' },
  { name: '橙色', value: '#FF6B35' },
  { name: '蓝色', value: '#5BC0EB' },
  { name: '黄色', value: '#FFD23F' },
]

const stickers = ['⭐', '🌈', '💪', '🎀', '🦁', '🌸']

export default function DIY() {
  const { diyDesign, updateDIYDesign, addSectionScore, sectionScores } = useStore()
  const [text, setText] = useState(diyDesign.text)
  const [saved, setSaved] = useState(false)

  const handleColorSelect = (color: string) => { updateDIYDesign({ color }) }
  const handleStickerSelect = (sticker: string) => { updateDIYDesign({ sticker }) }
  const handleTextChange = (value: string) => {
    const trimmed = value.slice(0, 8)
    setText(trimmed)
    updateDIYDesign({ text: trimmed })
  }

  const handleSave = () => {
    if (!saved) {
      addSectionScore('diy', DIY_POINTS)
      setSaved(true)
    }
  }

  const stickerMap: Record<string, string> = {
    star: '⭐', rainbow: '🌈', muscle: '💪',
    ribbon: '🎀', lion: '🦁', flower: '🌸',
  }
  const stickerKeyMap: Record<string, string> = {
    '⭐': 'star', '🌈': 'rainbow', '💪': 'muscle',
    '🎀': 'ribbon', '🦁': 'lion', '🌸': 'flower',
  }

  return (
    <div className="page-section flex flex-col items-center px-5 py-6 relative overflow-hidden"
      style={{ background: 'linear-gradient(135deg, #667eea 0%, #764ba2 30%, #f093fb 60%, #f5576c 80%, #ffd23f 100%)' }}>

      {/* 背景装饰 */}
      <div className="absolute inset-0 pointer-events-none">
        <div className="absolute top-10 left-5 w-20 h-20 rounded-full bg-white/10 blur-xl" />
        <div className="absolute top-40 right-3 w-16 h-16 rounded-full bg-yellow-300/20 blur-lg" />
        <div className="absolute bottom-32 left-8 w-24 h-24 rounded-full bg-pink-300/15 blur-xl" />
        <div className="absolute bottom-10 right-10 w-14 h-14 rounded-full bg-blue-300/20 blur-lg" />
      </div>

      {/* 标题 */}
      <h2 className="text-2xl font-bold text-white mb-1 z-10 font-display drop-shadow-lg">
        设计你的专属瓶身
      </h2>
      <p className="text-white/70 text-xs mb-4 z-10">保存设计 +{DIY_POINTS}分</p>

      {/* 瓶身预览 */}
      <div className="flex-1 flex items-center justify-center w-full max-w-xs mb-4 z-10">
        <div className="relative">
          {/* 瓶身光晕 */}
          <div className="absolute inset-0 blur-2xl opacity-40 rounded-full"
            style={{ background: diyDesign.color, transform: 'scale(1.3)' }} />
          <svg viewBox="0 0 120 240" className="bottle-shape w-32 h-auto relative z-10">
            <rect x="38" y="5" width="44" height="25" rx="6" fill="white" stroke="#ddd" strokeWidth="1" />
            <path d="M42 30 L42 55 L78 55 L78 30" fill={diyDesign.color} />
            <rect x="25" y="55" width="70" height="160" rx="12" fill={diyDesign.color} />
            {/* 高光 */}
            <rect x="28" y="60" width="15" height="140" rx="6" fill="white" opacity="0.25" />
            <rect x="32" y="100" width="56" height="60" rx="4" fill="white" fillOpacity="0.9" />
            {diyDesign.text && (
              <text x="60" y="135" textAnchor="middle" fontSize="11" fill="#333" fontWeight="bold">
                {diyDesign.text}
              </text>
            )}
            {diyDesign.sticker && stickerMap[diyDesign.sticker] && (
              <text x="60" y="85" textAnchor="middle" fontSize="18">
                {stickerMap[diyDesign.sticker]}
              </text>
            )}
          </svg>
        </div>
      </div>

      {/* 颜色选择 */}
      <div className="w-full mb-4 z-10">
        <p className="text-sm font-bold text-white/90 mb-2">选择颜色</p>
        <div className="flex justify-between">
          {colors.map((c) => (
            <button key={c.value} onClick={() => handleColorSelect(c.value)}
              className="w-10 h-10 rounded-full border-2 flex items-center justify-center transition-all active:scale-90 shadow-md"
              style={{
                backgroundColor: c.value,
                borderColor: diyDesign.color === c.value ? '#ffffff' : 'rgba(255,255,255,0.3)',
                borderWidth: diyDesign.color === c.value ? '3px' : '2px',
              }}>
              {diyDesign.color === c.value && <span className="text-white text-sm font-bold">✓</span>}
            </button>
          ))}
        </div>
      </div>

      {/* 贴纸选择 */}
      <div className="w-full mb-4 z-10">
        <p className="text-sm font-bold text-white/90 mb-2">选择贴纸</p>
        <div className="flex justify-between">
          {stickers.map((s) => (
            <button key={s} onClick={() => handleStickerSelect(stickerKeyMap[s])}
              className={`w-10 h-10 rounded-xl flex items-center justify-center text-xl transition-all active:scale-90 shadow-md ${
                diyDesign.sticker === stickerKeyMap[s]
                  ? 'bg-white/40 border-2 border-white'
                  : 'bg-white/15 border-2 border-white/30'
              }`}>
              {s}
            </button>
          ))}
        </div>
      </div>

      {/* 文字输入 */}
      <div className="w-full mb-4 z-10">
        <p className="text-sm font-bold text-white/90 mb-2">自定义文字（最多8字）</p>
        <input type="text" value={text} onChange={(e) => handleTextChange(e.target.value)}
          placeholder="输入你的文字..."
          className="w-full px-4 py-2 rounded-xl border-2 border-white/30 focus:border-white
            outline-none text-gray-700 bg-white/90 transition-colors placeholder:text-gray-400" />
      </div>

      {/* 保存按钮 */}
      <button onClick={handleSave} disabled={saved}
        className={`w-full py-3 rounded-full text-white font-bold text-base leading-normal shadow-lg
          active:scale-95 transition-transform z-10 ${
          saved
            ? 'bg-white/30 cursor-default'
            : 'bg-gradient-to-r from-yellow-400 via-pink-500 to-purple-500'
          }`}>
        {saved ? `已保存 +${DIY_POINTS}分 ✓` : `保存设计 +${DIY_POINTS}分`}
      </button>
    </div>
  )
}
