import { useState, useCallback } from 'react'
import { useStore } from '@/store/useStore'

// 口味数据 - 选择口味+10分
const FLAVOR_POINTS = 10

const flavors = [
  { name: '原味', color: '#00A850', emoji: '🥛', desc: '经典原味，童年的味道' },
  { name: '草莓味', color: '#FF6B8A', emoji: '🍓', desc: '甜蜜草莓，果香四溢' },
  { name: '巧克力味', color: '#8B4513', emoji: '🍫', desc: '浓郁巧克力，丝滑口感' },
  { name: '蜜桃味', color: '#FFB347', emoji: '🍑', desc: '清甜蜜桃，沁人心脾' },
]

interface Particle {
  id: number
  x: number
  y: number
  dx: number
  dy: number
  color: string
}

export default function Flavor() {
  const [selected, setSelected] = useState<string>('')
  const [particles, setParticles] = useState<Particle[]>([])
  const [bubble, setBubble] = useState<{ flavor: string; desc: string } | null>(null)
  const setFlavorChoice = useStore((s) => s.setFlavorChoice)
  const addSectionScore = useStore((s) => s.addSectionScore)
  const hasScored = useStore((s) => s.sectionScores.flavor > 0)

  const spawnParticles = useCallback((color: string, rect: DOMRect) => {
    const cx = rect.left + rect.width / 2
    const cy = rect.top + rect.height / 2
    const count = 8 + Math.floor(Math.random() * 5)
    const newParticles: Particle[] = Array.from({ length: count }, (_, i) => {
      const angle = (Math.PI * 2 * i) / count + Math.random() * 0.5
      const dist = 40 + Math.random() * 60
      return { id: Date.now() + i, x: cx, y: cy, dx: Math.cos(angle) * dist, dy: Math.sin(angle) * dist, color }
    })
    setParticles(newParticles)
    setTimeout(() => setParticles([]), 800)
  }, [])

  const handleClick = (flavor: typeof flavors[number], e: React.MouseEvent) => {
    setSelected(flavor.name)
    setFlavorChoice(flavor.name)
    // 只在首次选择时加分
    if (!hasScored) {
      addSectionScore('flavor', FLAVOR_POINTS)
    }
    spawnParticles(flavor.color, e.currentTarget.getBoundingClientRect())
    setBubble({ flavor: flavor.name, desc: flavor.desc })
    setTimeout(() => setBubble(null), 2000)
  }

  return (
    <div className="page-section flex flex-col items-center justify-center px-6 py-8"
      style={{ background: '#FFF8F0' }}>

      <h1 className="text-3xl font-display text-brand-green mb-2 animate-fade-in-up">
        选择你的口味
      </h1>
      <p className="text-sm text-brand-green/50 mb-6">选择口味 +{FLAVOR_POINTS}分</p>

      <div className="flex flex-col items-center gap-5 mb-6">
        {flavors.map((f) => (
          <button key={f.name} onClick={(e) => handleClick(f, e)}
            className={`relative w-20 h-20 rounded-full flex flex-col items-center justify-center
              text-white font-display text-sm shadow-lg transition-all duration-300 active:scale-110
              ${selected === f.name ? 'animate-pulse-glow ring-4 ring-offset-2' : ''}`}
            style={{
              background: f.color,
              boxShadow: selected === f.name ? `0 0 20px ${f.color}80` : undefined,
              outlineColor: selected === f.name ? f.color : undefined,
            }}>
            <span className="text-xl">{f.emoji}</span>
            <span className="text-xs mt-0.5">{f.name}</span>
          </button>
        ))}
      </div>

      {bubble && (
        <div className="bg-white rounded-2xl px-4 py-2 shadow-md mb-4 animate-fade-in-scale text-center">
          <p className="text-sm font-body" style={{ color: flavors.find(f => f.name === bubble.flavor)?.color }}>
            {bubble.desc}
          </p>
        </div>
      )}

      {selected && (
        <p className="text-base font-display text-brand-green mb-4 animate-fade-in-up">
          你选择了: {selected} {!hasScored && <span className="text-brand-orange text-sm">+{FLAVOR_POINTS}分</span>}
        </p>
      )}

      {particles.map((p) => (
        <div key={p.id} className="particle" style={{
          left: p.x, top: p.y, width: 10, height: 10, background: p.color,
          animation: `particleBurst 0.8s ease-out forwards`,
          '--dx': `${p.dx}px`, '--dy': `${p.dy}px`,
        } as React.CSSProperties} />
      ))}

      <div className="absolute bottom-6 flex flex-col items-center text-brand-green/50">
        <span className="text-xs font-body">向下滑动</span>
        <span className="scroll-hint text-lg">↓</span>
      </div>

      <style>{`
        @keyframes particleBurst {
          0% { transform: translate(0, 0) scale(1); opacity: 1; }
          100% { transform: translate(var(--dx), var(--dy)) scale(0); opacity: 0; }
        }
      `}</style>
    </div>
  )
}
