import { useState, useRef, useCallback } from 'react'
import { useStore } from '@/store/useStore'

const ITEMS = [
  { id: 'bottle', emoji: '🧃', label: 'AD钙奶', targetX: 120, targetY: 180 },
  { id: 'book', emoji: '📚', label: '课本', targetX: 200, targetY: 120 },
  { id: 'rope', emoji: '🪢', label: '跳绳', targetX: 60, targetY: 100 },
  { id: 'pencil', emoji: '✏️', label: '铅笔', targetX: 230, targetY: 200 },
  { id: 'bag', emoji: '🎒', label: '书包', targetX: 50, targetY: 200 },
]

const INIT_POS = [
  { x: 30, y: 20 }, { x: 260, y: 20 }, { x: 30, y: 450 },
  { x: 260, y: 450 }, { x: 145, y: 470 },
]

const MEMORY_POINTS_PER_ITEM = 10

export default function Memory() {
  const { addSectionScore, resetSectionScore } = useStore()
  const sceneRef = useRef<HTMLDivElement>(null)
  const [placed, setPlaced] = useState<Set<string>>(new Set())
  const [positions, setPositions] = useState(INIT_POS.map((p) => ({ ...p })))
  const [dragging, setDragging] = useState<number | null>(null)
  const [offset, setOffset] = useState({ x: 0, y: 0 })
  const [particles, setParticles] = useState<{ id: number; x: number; y: number; color: string }[]>([])
  const [celebrating, setCelebrating] = useState(false)
  const [titleVisible, setTitleVisible] = useState(false)
  const [earnedScore, setEarnedScore] = useState(0)

  useState(() => { setTimeout(() => setTitleVisible(true), 100) })

  const checkDrop = useCallback((idx: number, x: number, y: number) => {
    if (!sceneRef.current) return false
    const rect = sceneRef.current.getBoundingClientRect()
    const relX = x - rect.left
    const relY = y - rect.top
    return relX >= 0 && relX <= 300 && relY >= 0 && relY <= 300
  }, [])

  const spawnParticles = useCallback((x: number, y: number) => {
    const colors = ['#FFD23F', '#FF6B35', '#00A850', '#5BC0EB', '#FF9ECD']
    const newP = Array.from({ length: 8 }, (_, i) => ({
      id: Date.now() + i,
      x: x + (Math.random() - 0.5) * 60,
      y: y + (Math.random() - 0.5) * 60,
      color: colors[i % colors.length],
    }))
    setParticles((prev) => [...prev, ...newP])
    setTimeout(() => setParticles((prev) => prev.filter((p) => !newP.find((np) => np.id === p.id))), 1500)
  }, [])

  const spawnConfetti = useCallback(() => {
    setCelebrating(true)
    const colors = ['#FFD23F', '#FF6B35', '#00A850', '#5BC0EB', '#FF9ECD']
    const confetti = Array.from({ length: 30 }, (_, i) => ({
      id: Date.now() + i, x: Math.random() * 300, y: Math.random() * 300, color: colors[i % colors.length],
    }))
    setParticles(confetti)
    setTimeout(() => { setParticles([]); setCelebrating(false) }, 2500)
  }, [])

  const handleDragStart = (idx: number, clientX: number, clientY: number) => {
    setDragging(idx)
    setOffset({ x: clientX - positions[idx].x, y: clientY - positions[idx].y })
  }

  const handleDragMove = (clientX: number, clientY: number) => {
    if (dragging === null) return
    setPositions((prev) => { const next = [...prev]; next[dragging] = { x: clientX - offset.x, y: clientY - offset.y }; return next })
  }

  const handleDragEnd = (idx: number, clientX: number, clientY: number) => {
    setDragging(null)
    if (placed.has(ITEMS[idx].id)) return
    if (checkDrop(idx, clientX, clientY)) {
      setPlaced((prev) => { const next = new Set(prev); next.add(ITEMS[idx].id); if (next.size === 5) spawnConfetti(); return next })
      setPositions((prev) => {
        const next = [...prev]
        const rect = sceneRef.current!.getBoundingClientRect()
        next[idx] = { x: rect.left + ITEMS[idx].targetX, y: rect.top + ITEMS[idx].targetY }
        return next
      })
      addSectionScore('memory', MEMORY_POINTS_PER_ITEM)
      setEarnedScore(prev => prev + MEMORY_POINTS_PER_ITEM)
      spawnParticles(clientX, clientY)
    }
  }

  const handleReset = () => {
    resetSectionScore('memory')
    setPlaced(new Set())
    setPositions(INIT_POS.map((p) => ({ ...p })))
    setParticles([])
    setCelebrating(false)
    setEarnedScore(0)
  }

  return (
    <div className="page-section flex flex-col items-center"
      style={{ background: 'linear-gradient(180deg, #FFF8DC 0%, #FFF5E1 40%, #FFECD2 100%)' }}>
      <h1 className={`text-3xl font-bold text-amber-700 mt-6 mb-1 transition-all duration-700 ${titleVisible ? 'translate-x-0 opacity-100' : '-translate-x-20 opacity-0'}`}>
        童年回忆
      </h1>
      <p className="text-amber-600 text-xs mb-3">把物品拖到教室场景中 +{MEMORY_POINTS_PER_ITEM}分/个</p>

      <div ref={sceneRef} className="relative rounded-2xl overflow-hidden border-4 border-amber-300 shadow-lg"
        style={{ width: 300, height: 300 }}>
        <div className="absolute inset-0" style={{ background: 'linear-gradient(180deg, #87CEEB 0%, #87CEEB 55%, #8B7355 55%, #8B7355 100%)' }}>
          <div className="absolute" style={{ left: 40, top: 30, width: 220, height: 100, background: '#2E5E3E', borderRadius: 6, border: '6px solid #8B6914' }}>
            <div className="text-white text-center text-xs mt-6">欢迎回到童年</div>
          </div>
          <div className="absolute" style={{ left: 20, top: 220, width: 260, height: 2, background: '#fff' }} />
          <div className="absolute" style={{ left: 100, top: 180, width: 100, height: 100, border: '2px solid #fff', borderRadius: '50%' }} />
        </div>
        {ITEMS.map((item) => placed.has(item.id) && (
          <span key={item.id} className="absolute text-3xl animate-bounce" style={{ left: item.targetX - 16, top: item.targetY - 16 }}>{item.emoji}</span>
        ))}
        {particles.map((p) => (
          <div key={p.id} className="particle" style={{ left: p.x, top: p.y, width: 8, height: 8, background: p.color }} />
        ))}
      </div>

      <div className="mt-3 text-amber-700 font-bold text-sm">
        {placed.size}/5 已放置 | +{earnedScore}分
      </div>

      {placed.size === 5 && (
        <div className="absolute inset-0 flex items-center justify-center z-20 pointer-events-none">
          <div className="text-4xl font-bold text-amber-600 animate-pulse">回忆完成! 🎉</div>
        </div>
      )}

      {ITEMS.map((item, idx) => (
        <div key={item.id}
          className={`absolute z-10 flex flex-col items-center select-none ${placed.has(item.id) ? 'opacity-40' : 'cursor-grab active:cursor-grabbing'}`}
          style={{ left: positions[idx].x - 24, top: positions[idx].y - 24, fontSize: 40, touchAction: 'none' }}
          onTouchStart={(e) => { if (!placed.has(item.id)) handleDragStart(idx, e.touches[0].clientX, e.touches[0].clientY) }}
          onTouchMove={(e) => { if (dragging === idx) { e.preventDefault(); handleDragMove(e.touches[0].clientX, e.touches[0].clientY) } }}
          onTouchEnd={() => { if (dragging === idx) handleDragEnd(idx, positions[idx].x + 24, positions[idx].y + 24) }}
          onMouseDown={(e) => { if (!placed.has(item.id)) handleDragStart(idx, e.clientX, e.clientY) }}
          onMouseMove={(e) => { if (dragging === idx) handleDragMove(e.clientX, e.clientY) }}
          onMouseUp={(e) => { if (dragging === idx) handleDragEnd(idx, e.clientX, e.clientY) }}>
          <span>{item.emoji}</span>
          <span className="text-xs text-amber-700">{item.label}</span>
        </div>
      ))}

      <button onClick={handleReset}
        className="absolute bottom-8 px-6 py-2 rounded-full bg-amber-500 text-white font-bold shadow-lg active:scale-95 transition-transform text-sm">
        重新开始
      </button>
    </div>
  )
}
