import { useRef, useCallback, useEffect } from 'react'
import Cover from '@/pages/Cover'
import Impression from '@/pages/Impression'
import Product from '@/pages/Product'
import Flavor from '@/pages/Flavor'
import Memory from '@/pages/Memory'
import Game from '@/pages/Game'
import AR from '@/pages/AR'
import Story from '@/pages/Story'
import Quiz from '@/pages/Quiz'
import DIY from '@/pages/DIY'
import Share from '@/pages/Share'
import Rules from '@/pages/Rules'
import { useStore } from '@/store/useStore'

const pages = [
  Cover,
  Impression,
  Product,
  Flavor,
  Memory,
  Game,
  AR,
  Story,
  Quiz,
  DIY,
  Share,
  Rules,
]

const pageNames = [
  '封面',
  '品牌印象',
  '产品展示',
  '口味互动',
  '童年回忆',
  '钙力挑战',
  'AR体验',
  '品牌故事',
  '营养问答',
  'DIY瓶身',
  '分享海报',
  '活动规则',
]

export default function App() {
  const sliderRef = useRef<HTMLDivElement>(null)
  const programmaticScroll = useRef(false)
  const { currentPage, score, setCurrentPage } = useStore()

  // 核心：滚动到指定页面
  const doScrollTo = useCallback((index: number) => {
    const el = sliderRef.current
    if (!el) return
    programmaticScroll.current = true
    el.scrollTo({ top: index * el.clientHeight, behavior: 'smooth' })
    setTimeout(() => { programmaticScroll.current = false }, 1000)
  }, [])

  // 导航点点击
  const scrollToPage = useCallback(
    (index: number) => {
      setCurrentPage(index)
      doScrollTo(index)
    },
    [setCurrentPage, doScrollTo]
  )

  // 监听 store 中 currentPage 变化，执行滚动
  useEffect(() => {
    doScrollTo(currentPage)
  }, [currentPage, doScrollTo])

  // 手动滑动时同步 currentPage
  const handleScroll = useCallback(() => {
    if (programmaticScroll.current) return
    const el = sliderRef.current
    if (!el) return
    const newIndex = Math.round(el.scrollTop / el.clientHeight)
    if (newIndex !== currentPage && newIndex >= 0 && newIndex < pages.length) {
      setCurrentPage(newIndex)
    }
  }, [currentPage, setCurrentPage])

  return (
    <>
      {/* 横屏提示 */}
      <div className="landscape-warning">
        <span className="text-4xl">📱</span>
        <p className="font-display text-lg">请竖屏浏览</p>
        <p className="text-sm opacity-80">获得最佳体验效果</p>
      </div>

      {/* 积分浮窗 */}
      <div className="fixed top-3 right-3 z-50 bg-white/90 backdrop-blur-sm rounded-full px-3 py-1 shadow-lg flex items-center gap-1">
        <span className="text-brand-yellow text-sm">⭐</span>
        <span className="text-brand-green font-bold text-sm">{score}</span>
      </div>

      {/* 页面导航点 */}
      <div className="fixed right-2 top-1/2 -translate-y-1/2 z-50 flex flex-col gap-1.5">
        {pageNames.map((_, i) => (
          <button
            key={i}
            onClick={() => scrollToPage(i)}
            className={`w-2 h-2 rounded-full transition-all duration-300 ${
              i === currentPage
                ? 'bg-brand-green scale-150'
                : 'bg-brand-green/30'
            }`}
            title={pageNames[i]}
          />
        ))}
      </div>

      {/* 页面滑动容器 */}
      <div
        ref={sliderRef}
        className="page-slider"
        onScroll={handleScroll}
      >
        {pages.map((Page, index) => (
          <div key={index} className={index === pages.length - 1 ? 'page-section-scrollable' : 'page-section'}>
            <Page />
          </div>
        ))}
      </div>
    </>
  )
}
