import { useEffect, useRef, useState, useCallback } from 'react'
import { useStore } from '@/store/useStore'
import { timelineData } from '@/data/timeline'

export default function Story() {
  const { addScore } = useStore()
  const [visibleItems, setVisibleItems] = useState<Set<number>>(new Set())
  const [bottomScored, setBottomScored] = useState(false)
  const itemRefs = useRef<(HTMLDivElement | null)[]>([])
  const scrollRef = useRef<HTMLDivElement>(null)

  // IntersectionObserver 监听时间线项进入视口
  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          const index = Number(entry.target.getAttribute('data-index'))
          if (entry.isIntersecting) {
            setVisibleItems((prev) => new Set(prev).add(index))
          }
        })
      },
      { root: scrollRef.current, threshold: 0.3 }
    )

    itemRefs.current.forEach((el) => {
      if (el) observer.observe(el)
    })

    return () => observer.disconnect()
  }, [])

  // 滚动到底部加分
  const handleScroll = useCallback(() => {
    const el = scrollRef.current
    if (!el || bottomScored) return
    if (el.scrollHeight - el.scrollTop - el.clientHeight < 50) {
      setBottomScored(true)
      addScore(5)
    }
  }, [bottomScored, addScore])

  return (
    <div className="page-section flex flex-col"
      style={{ background: 'linear-gradient(180deg, #ffffff 0%, #e8f5e9 100%)' }}>

      {/* 标题 */}
      <h1 className="text-2xl font-bold text-center pt-8 pb-4 text-gray-800 shrink-0"
        style={{ animation: 'fadeIn 0.8s ease-out' }}>
        品牌故事
      </h1>

      {/* 可滚动时间线区域 */}
      <div ref={scrollRef} onScroll={handleScroll}
        className="flex-1 overflow-y-auto relative px-4 pb-8"
        style={{ WebkitOverflowScrolling: 'touch' }}>

        {/* 时间线竖线 */}
        <div className="timeline-line" />

        {/* 时间线项 */}
        {timelineData.map((item, index) => {
          const isLeft = index % 2 === 0
          const visible = visibleItems.has(index)

          return (
            <div key={index} data-index={index}
              ref={(el) => { itemRefs.current[index] = el }}
              className={`relative flex items-start mb-8 ${isLeft ? 'flex-row' : 'flex-row-reverse'}`}
              style={{
                opacity: visible ? 1 : 0,
                transform: visible ? 'translateY(0)' : 'translateY(20px)',
                transition: 'all 0.6s ease-out',
              }}>

              {/* 内容卡片 */}
              <div className={`w-[42%] ${isLeft ? 'text-right pr-4' : 'text-left pl-4'}`}>
                <div className="text-xl font-bold" style={{ color: item.color }}>
                  {item.year}
                </div>
                <div className="text-sm font-bold text-gray-800 mt-1">{item.title}</div>
                <div className="text-xs text-gray-500 mt-1 leading-relaxed">
                  {item.description}
                </div>
              </div>

              {/* 中间圆点 */}
              <div className="timeline-dot shrink-0"
                style={{
                  background: item.color,
                  boxShadow: `0 0 0 3px ${item.color}`,
                  top: '4px',
                }} />

              {/* 占位 */}
              <div className="w-[42%]" />
            </div>
          )
        })}

        {/* 底部未完待续 */}
        <p className="text-center text-gray-400 text-sm pt-4 pb-8 animate-pulse">
          未完待续...
        </p>
      </div>

      {/* 淡入动画 */}
      <style>{`
        @keyframes fadeIn {
          from { opacity: 0; transform: translateY(-10px); }
          to { opacity: 1; transform: translateY(0); }
        }
      `}</style>
    </div>
  )
}
