import { useStore } from '@/store/useStore'

// 飘浮的钙滴装饰
const floatingDrops = Array.from({ length: 6 }, (_, i) => ({
  id: i,
  left: `${10 + i * 15}%`,
  delay: `${i * 0.5}s`,
  size: 8 + (i % 3) * 4,
}))

// 装饰性星星
const decorStars = Array.from({ length: 5 }, (_, i) => ({
  id: i,
  left: `${5 + i * 20}%`,
  top: `${10 + (i % 3) * 25}%`,
  delay: `${i * 0.3}s`,
  size: 6 + (i % 2) * 4,
}))

export default function Cover() {
  const setCurrentPage = useStore((s) => s.setCurrentPage)

  const handleEnter = () => {
    setCurrentPage(1)
  }

  return (
    <section className="page-section bg-brand-gradient flex flex-col items-center justify-center relative overflow-hidden">
      {/* 飘浮钙滴 - pointer-events-none 防止遮挡点击 */}
      {floatingDrops.map((d) => (
        <div
          key={d.id}
          className="absolute rounded-full bg-brand-blue/40 animate-float pointer-events-none"
          style={{
            left: d.left,
            top: `${20 + (d.id % 3) * 20}%`,
            width: d.size,
            height: d.size,
            animationDelay: d.delay,
          }}
        />
      ))}

      {/* 装饰星星 - pointer-events-none */}
      {decorStars.map((s) => (
        <div
          key={s.id}
          className="absolute text-brand-yellow/60 animate-float-slow pointer-events-none"
          style={{ left: s.left, top: s.top, animationDelay: s.delay, fontSize: s.size }}
        >
          ✦
        </div>
      ))}

      {/* 品牌标题 */}
      <h1 className="font-display text-4xl text-white drop-shadow-lg animate-fade-in-scale mb-2 z-10">
        哇哈哈AD钙奶
      </h1>

      {/* 副标题 */}
      <p className="font-display text-lg text-white/90 animate-fade-in-up z-10"
        style={{ animationDelay: '0.4s', opacity: 0, animationFillMode: 'forwards' }}>
        童年味道 钙力全开
      </p>

      {/* 瓶子SVG */}
      <div className="my-6 animate-float z-10 pointer-events-none">
        <svg
          className="bottle-shape w-28 h-48"
          viewBox="0 0 120 200"
          fill="none"
          xmlns="http://www.w3.org/2000/svg"
        >
          {/* 瓶盖 */}
          <rect x="38" y="4" width="44" height="24" rx="6" fill="white" stroke="#ddd" strokeWidth="1" />
          <rect x="42" y="0" width="36" height="10" rx="4" fill="#f0f0f0" stroke="#ddd" strokeWidth="1" />
          {/* 瓶颈 */}
          <path d="M44 28 L44 50 Q44 55 38 58 L38 58 Q32 60 32 65 L32 70" fill="#00A850" stroke="#008040" strokeWidth="1" />
          <path d="M76 28 L76 50 Q76 55 82 58 L82 58 Q88 60 88 65 L88 70" fill="#00A850" stroke="#008040" strokeWidth="1" />
          {/* 瓶身 */}
          <rect x="30" y="68" width="60" height="110" rx="12" fill="#00A850" stroke="#008040" strokeWidth="1.5" />
          {/* 标签区域 */}
          <rect x="34" y="95" width="52" height="55" rx="6" fill="white" opacity="0.9" />
          <text x="60" y="118" textAnchor="middle" fill="#00A850" fontSize="11" fontWeight="bold" fontFamily="'ZCOOL KuaiLe', cursive">
            AD钙奶
          </text>
          <text x="60" y="138" textAnchor="middle" fill="#33CC66" fontSize="8" fontFamily="'ZCOOL KuaiLe', cursive">
            哇哈哈
          </text>
          {/* 瓶底 */}
          <rect x="30" y="172" width="60" height="14" rx="7" fill="#008040" />
        </svg>
      </div>

      {/* 点击进入按钮 - 高z-index确保可点击，去掉冲突动画 */}
      <button
        onClick={handleEnter}
        className="relative z-50 px-8 py-3 rounded-full font-display text-white text-lg
          bg-gradient-to-r from-brand-orange to-brand-yellow
          shadow-lg hover:shadow-xl
          transition-all duration-300
          active:scale-95
          animate-pulse-glow mt-2"
      >
        点击进入
      </button>

      {/* 滚动提示箭头 */}
      <div className="absolute bottom-6 left-1/2 -translate-x-1/2 scroll-hint text-white/70 z-10 pointer-events-none">
        <svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round">
          <path d="M6 9l6 6 6-6" />
        </svg>
      </div>
    </section>
  )
}
